  await page.click('button[type="submit"]');
  await new Promise(r => setTimeout(r, 6000));

  console.log('✅ Login complete. URL:', page.url());
}

async function setupProfile(page) {
  console.log('🔵 Navigating to profile settings...');
  await page.goto('https://www.fiverr.com/users/edit', { waitUntil: 'networkidle', timeout: 30000 });
  await humanDelay(3000);

  const title = await page.inputValue('input[name="headline"]').catch(() => '');
  const description = await page.inputValue('textarea[name="description"]').catch(() => '');
  const fullName = await page.inputValue('input[name="full_name"]').catch(() => '');

  console.log('📋 Current profile state:');
  console.log('   Headline:', title || '(empty)');
  console.log('   Full name:', fullName || '(empty)');
  console.log('   Description length:', description.length);

  if (!title && !description) {
    console.log('⚠️ Profile needs setup — will update with Rebecca Ashford info');
    await updateProfileFull(page);
    return;
  }

  console.log('✅ Profile already configured!');
}

async function updateProfileFull(page) {
  console.log('🔵 Updating profile...');

  await page.fill('input[name="headline"]', 'UGC Creator | Fashion & Lifestyle Influencer | Lookitry Ambassador');
  await new Promise(r => setTimeout(r, 1000));

  await page.fill('input[name="full_name"]', 'Rebecca Ashford');
  await new Promise(r => setTimeout(r, 1000));

  const description = `Hi! I'm Rebecca 👋

UGC Creator & Fashion Influencer helping brands connect with their audience through authentic, engaging content.

✅ What I offer:
• Lifestyle & Fashion content
• Product testimonials (UGC style)
• Spokesperson videos
• Lipsync content
• TikTok & Instagram Reels

🌟 Featured Ambassador at @lookitry_ — the AI-powered fashion tool for retail stores.

Let's create something amazing together!`;

  await page.fill('textarea[name="description"]', description);
  await new Promise(r => setTimeout(r, 1000));

  console.log('🔵 Saving profile...');
  await page.click('button[type="submit"]');
  await new Promise(r => setTimeout(r, 3000));

  console.log('✅ Profile updated!');
}

async function main() {
  console.log('🚀 Fiverr Automation Starting...\n');

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
    viewport: { width: 1280, height: 720 },
    ignoreHTTPSErrors: true
  });
  const page = await context.newPage();

  page.on('response', response => {
    if (response.url().includes('perimeterx') || response.url().includes('captcha')) {
      console.log('🚨 Challenge detected at:', response.url());
    }
  });

  try {
    await login(page);
    await setupProfile(page);

    await context.storageState({ path: SESSION_FILE });
    console.log(`\n💾 Session saved to ${SESSION_FILE}`);
    console.log('\n✅ All done!');

  } catch (error) {
    console.error('❌ Error:', error.message);
  } finally {
    await browser.close();
  }
}

main().catch(console.error);

