      els.slice(0, 10).map(e => ({ text: e.innerText?.slice(0, 80), href: e.href }))
    );
    console.log('\nTop results:');
    links.forEach(l => console.log('-', l.text, '|', l.href));
  } catch(e) {
    console.log('Search error:', e.message);
  }

  await browser.close();
  console.log('\nDone!');
})();
